{"content": "import argparse
import sys

def format_result(val):
    if val == int(val):
        return str(int(val))
    return str(val)

def main():
    parser = argparse.ArgumentParser(description="Tiny calculator CLI")
    subparsers = parser.add_subparsers(dest="command", required=True)

    # Add
    add_parser = subparsers.add_parser("add")
    add_parser.add_argument("a", type=float)
    add_parser.add_argument("b", type=float)

    # Sub
    sub_parser = subparsers.add_parser("sub")
    sub_parser.add_argument("a", type=float)
    sub_parser.add_argument("b", type=float)

    # Mul
    mul_parser = subparsers.add_parser("mul")
    mul_parser.add_argument("a", type=float)
    mul_parser.add_argument("b", type=float)

    # Div
    div_parser = subparsers.add_parser("div")
    div_parser.add_argument("a", type=float)
    div_parser.add_argument("b", type=float)

    args = parser.parse_args()

    if args.command == "add":
        print(format_result(args.a + args.b))
    elif args.command == "sub":
        print(format_result(args.a - args.b))
    elif args.command == "mul":
        print(format_result(args.a * args.b))
    elif args.command == "div":
        if args.b == 0:
            print("Error: Division by zero", file=sys.stderr)
            sys.exit(1)
        print(format_result(args.a / args.b))

if __name__ == "__main__":
    main()
